// @ts-nocheck
/** Group Query — runs one read-only SQL across every connection in a connection group.
 *  Results render with the same grid + export (CSV/JSON/SQL) as the single query editor.
 *  Supports a "View all" mode that stacks every connection's result set at once. */
import React, { useState, useRef, useCallback, useMemo } from 'react';
import { Play, ChevronRight, ChevronDown, CheckCircle2, AlertCircle, Loader2, Database, Download, Copy as CopyIcon, ChevronDown as Caret, Layers } from 'lucide-react';
import Editor from '@monaco-editor/react';
import { api } from '../../lib/api';
import { notify } from '../../lib/notify';
import { useThemeStore } from '../../store/theme';
import {
  FO,
  uH,
  qSortKeys,
  du,
  nH,
  resultSetClipboardText,
  copyResultSetToClipboard,
} from '../bundle';

const MAX_ROWS = 500;

function safeName(s: string): string {
  return String(s ?? '').replace(/\s+/g, '_').replace(/[^\w.-]/g, '');
}

function downloadText(content: string, filename: string, type: string) {
  const url = URL.createObjectURL(new Blob([content], { type }));
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

/** Aggregate every successful connection's result set into one file. */
function exportAllConnections(format: 'csv' | 'json' | 'sql', groupName: string, results: any[]) {
  const ok = results.filter((r) => r.ok && r.statements?.[0]?.columns?.length > 0);
  if (!ok.length) {
    notify('No result sets to export', `Group Query · ${groupName}`);
    return;
  }
  const stamp = new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-');
  const base = `group-${safeName(groupName)}-${stamp}`;
  if (format === 'json') {
    const data = ok.map((r) => ({
      connection: r.name,
      engine: r.engine,
      columns: r.statements[0].columns,
      rows: r.statements[0].rows,
    }));
    downloadText(JSON.stringify(data, null, 2), `${base}.json`, 'application/json');
    notify(`Exported ${ok.length} connection(s) as JSON`, `Group Query · ${groupName}`);
    return;
  }
  if (format === 'sql') {
    const parts = ok.map((r) => {
      const rs = { columns: r.statements[0].columns, rows: r.statements[0].rows };
      return `-- Connection: ${r.name} (${r.engine})\n` + nH(rs, `result_${safeName(r.name)}`);
    });
    downloadText(parts.join('\n\n'), `${base}.sql`, 'application/sql;charset=utf-8');
    notify(`Exported ${ok.length} connection(s) as SQL`, `Group Query · ${groupName}`);
    return;
  }
  const sections = ok.map((r) => {
    const rs = { columns: r.statements[0].columns, rows: r.statements[0].rows };
    return `# Connection: ${r.name} (${r.engine})\n` + resultSetClipboardText('csv', rs);
  });
  downloadText(sections.join('\n\n'), `${base}.csv`, 'text/csv;charset=utf-8');
  notify(`Exported ${ok.length} connection(s) as CSV`, `Group Query · ${groupName}`);
}

export function GroupQueryPanel({
  groupId,
  groupName,
  initialSql = '',
}: {
  tabId?: string;
  groupId: string;
  groupName: string;
  initialSql?: string;
}) {
  const { theme } = useThemeStore();
  const [sql, setSql] = useState(initialSql || 'SELECT 1;');
  const [running, setRunning] = useState(false);
  const [response, setResponse] = useState<any>(null);
  const [error, setError] = useState('');
  const [expanded, setExpanded] = useState<string | null>(null);
  const [viewAll, setViewAll] = useState(false);
  const editorRef = useRef<any>(null);
  const runId = useRef(0);

  const onMount = (editor: any) => {
    editorRef.current = editor;
  };

  const run = useCallback(async () => {
    let q = (editorRef.current?.getModel()?.getValueInRange(editorRef.current.getSelection()) || '').trim();
    if (!q) q = sql.trim();
    if (!q) return;
    if (/^(SELECT|WITH)\b/i.test(q) && !/\bLIMIT\s+\d+/i.test(q) && !q.includes(';')) {
      q = `${q} LIMIT 2000`;
    }
    const id = ++runId.current;
    setRunning(true);
    setError('');
    setResponse(null);
    try {
      const res = await api.groupExecute(groupId, q, null, true);
      if (id !== runId.current) return;
      setResponse(res);
      const ok = (res.results ?? []).filter((r: any) => r.ok).length;
      const fail = (res.results ?? []).length - ok;
      notify(`${ok} OK · ${fail} failed · ${res.totalMs}ms`, `Group Query · ${groupName}`);
      const firstFail = (res.results ?? []).find((r: any) => !r.ok);
      if (firstFail) setExpanded(firstFail.connectionId);
      else if (res.results?.[0]) setExpanded(res.results[0].connectionId);
    } catch (e: any) {
      if (id !== runId.current) return;
      setError(e?.message ?? String(e));
      notify(e?.message ?? String(e), `Group Query · ${groupName}`);
    } finally {
      if (id === runId.current) setRunning(false);
    }
  }, [groupId, groupName, sql]);

  const results: any[] = response?.results ?? [];
  const okCount = results.filter((r) => r.ok).length;
  const exportableCount = results.filter((r) => r.ok && r.statements?.[0]?.columns?.length > 0).length;

  return (
    <div className="flex flex-col h-full min-h-0">
      <div className="px-2 py-1.5 flex items-center gap-2 border-b border-nv-border bg-nv-toolbar text-xs flex-wrap">
        <Database size={12} className="text-violet-500" />
        <span className="font-semibold">Group Query</span>
        <span className="text-nv-textSubtle">· {groupName}</span>
        <span className="text-nv-textMuted text-2xs">read-only · runs across {results.length || 'all'} connections</span>
        <div className="ml-auto flex items-center gap-2">
          {response && (
            <span className="text-2xs text-nv-textSubtle">
              {okCount}/{results.length} ok · {response.totalMs}ms
            </span>
          )}
          {results.length > 0 && (
            <button
              className={`nv-btn !py-0.5 flex items-center gap-1 ${viewAll ? 'bg-nv-accent text-white' : ''}`}
              onClick={() => setViewAll((v) => !v)}
              title="Stack every connection's result set at once"
            >
              <Layers size={11} /> View all
            </button>
          )}
          {exportableCount > 0 && (
            <div className="flex items-center gap-1 border-l border-nv-border pl-2 ml-1">
              <span className="text-2xs text-nv-textMuted">Export all:</span>
              <button className="nv-btn !py-0.5" onClick={() => exportAllConnections('csv', groupName, results)} title="Download all connections as CSV">CSV</button>
              <button className="nv-btn !py-0.5" onClick={() => exportAllConnections('json', groupName, results)} title="Download all connections as JSON">JSON</button>
              <button className="nv-btn !py-0.5" onClick={() => exportAllConnections('sql', groupName, results)} title="Download all connections as SQL (INSERT)">SQL</button>
            </div>
          )}
          <button className="nv-btn-primary flex items-center gap-1" onClick={run} disabled={running}>
            {running ? <Loader2 size={11} className="animate-spin" /> : <Play size={11} />}
            Run
          </button>
        </div>
      </div>

      <div style={{ height: '38%', minHeight: 120 }} className="border-b border-nv-border">
        <Editor
          height="100%"
          defaultLanguage="sql"
          theme={theme === 'dark' ? 'vs-dark' : 'vs'}
          value={sql}
          onChange={(v) => setSql(v ?? '')}
          onMount={onMount}
          options={{
            minimap: { enabled: false },
            fontSize: 12,
            fontFamily: 'SF Mono, Menlo, Monaco, Consolas, monospace',
            lineNumbers: 'on',
            scrollBeyondLastLine: false,
            automaticLayout: true,
            tabSize: 2,
          }}
        />
      </div>

      <div className="flex-1 min-h-0 overflow-auto bg-nv-panel">
        {error && (
          <div className="m-2 px-2 py-1.5 text-xs rounded border border-nv-danger/40 bg-nv-danger/10 text-nv-danger flex items-start gap-2">
            <AlertCircle size={12} className="mt-0.5 shrink-0" />
            <span className="break-all">{error}</span>
          </div>
        )}
        {!error && !response && (
          <div className="p-6 text-center text-xs text-nv-textMuted">
            Run a read-only query (SELECT / SHOW / DESCRIBE / EXPLAIN / WITH). It executes against every connection in
            the group <span className="text-nv-textSubtle">{groupName}</span>, using each connection's default database.
          </div>
        )}
        {viewAll && results.length > 0 ? (
          <div className="divide-y divide-nv-border">
            {results.map((r) => (
              <AllViewSection key={r.connectionId} r={r} groupName={groupName} />
            ))}
          </div>
        ) : (
          results.map((r) => (
            <ResultCard
              key={r.connectionId}
              r={r}
              groupName={groupName}
              expanded={expanded === r.connectionId}
              onToggle={() => setExpanded(expanded === r.connectionId ? null : r.connectionId)}
            />
          ))
        )}
      </div>
    </div>
  );
}

/** Shared body: error / no-rows / export toolbar + FO grid. Owns sort + copy-menu state. */
function ResultBody({ r, groupName }: { r: any; groupName: string }) {
  const [sort, setSort] = useState<any[]>([]);
  const [copyMenuOpen, setCopyMenuOpen] = useState(false);
  const stmt = r.ok && r.statements?.length ? r.statements[0] : null;
  const result = useMemo(
    () => (stmt ? { columns: stmt.columns ?? [], rows: stmt.rows ?? [] } : null),
    [stmt],
  );
  const sorted = useMemo(() => (result ? uH(result, sort) : null), [result, sort]);
  const hasRows = (result?.columns.length ?? 0) > 0;
  const rowCount = result?.rows.length ?? 0;
  const fileBase = `group-${safeName(groupName)}-${safeName(r.name)}`;

  const closeMenu = () => setCopyMenuOpen(false);

  return (
    <div className="px-2 pb-2">
      {!r.ok && <div className="text-xs text-nv-danger break-all px-1 py-1 font-mono">{r.error}</div>}
      {r.ok && !hasRows && (
        <div className="text-xs text-nv-textMuted px-1 py-1">
          {stmt?.message || 'No result set.'} · {r.totalTimeMs}ms
        </div>
      )}
      {r.ok && hasRows && sorted && (
        <>
          <div className="flex items-center gap-1 mb-1 text-2xs flex-wrap">
            <span className="text-nv-textMuted mr-1">{rowCount} row{rowCount === 1 ? '' : 's'}{rowCount > MAX_ROWS ? ` (first ${MAX_ROWS} shown)` : ''}</span>
            <div className="relative">
              <button
                className="nv-btn !py-0.5 flex items-center gap-0.5"
                onClick={() => setCopyMenuOpen((v) => !v)}
                title="Copy results to clipboard"
              >
                <CopyIcon size={11} /> Copy <Caret size={10} />
              </button>
              {copyMenuOpen && (
                <>
                  <div className="fixed inset-0 z-40" onClick={closeMenu} />
                  <div className="absolute right-0 top-full mt-0.5 z-50 bg-nv-panel border border-nv-border rounded shadow-lg py-0.5 min-w-[7rem]">
                    <button type="button" className="block w-full text-left px-2 py-1 text-2xs hover:bg-nv-hover" onClick={() => { copyResultSetToClipboard('csv', result); closeMenu(); }}>CSV</button>
                    <button type="button" className="block w-full text-left px-2 py-1 text-2xs hover:bg-nv-hover" onClick={() => { copyResultSetToClipboard('json', result); closeMenu(); }}>JSON</button>
                    <button type="button" className="block w-full text-left px-2 py-1 text-2xs hover:bg-nv-hover" onClick={() => { copyResultSetToClipboard('sql', result); closeMenu(); }}>SQL (INSERT)</button>
                  </div>
                </>
              )}
            </div>
            <button className="nv-btn !py-0.5 flex items-center gap-0.5" onClick={() => du('csv', result, fileBase)} title="Download CSV"><Download size={11} /> CSV</button>
            <button className="nv-btn !py-0.5 flex items-center gap-0.5" onClick={() => du('json', result, fileBase)} title="Download JSON"><Download size={11} /> JSON</button>
            <button className="nv-btn !py-0.5 flex items-center gap-0.5" onClick={() => du('sql', result, fileBase)} title="Download SQL (INSERT)"><Download size={11} /> SQL</button>
          </div>
          <div className="nv-group-grid border border-nv-border rounded overflow-hidden">
            <FO
              result={sorted}
              sort={sort}
              onSort={(col: string, shift: boolean) => setSort((prev) => qSortKeys(col, shift, prev))}
            />
          </div>
        </>
      )}
    </div>
  );
}

function ResultCard({ r, groupName, expanded, onToggle }: { r: any; groupName: string; expanded: boolean; onToggle: () => void }) {
  const stmt = r.ok && r.statements?.length ? r.statements[0] : null;
  const hasRows = (stmt?.columns?.length ?? 0) > 0;
  const rowCount = stmt?.rows?.length ?? 0;
  return (
    <div className="border-b border-nv-border">
      <button onClick={onToggle} className="w-full px-2 py-1.5 flex items-center gap-2 text-xs hover:bg-nv-hover text-left">
        {expanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
        {r.ok ? <CheckCircle2 size={12} className="text-nv-success" /> : <AlertCircle size={12} className="text-nv-danger" />}
        <span className="font-mono font-medium truncate flex-1">{r.name}</span>
        <span className="text-2xs text-nv-textMuted">{r.engine}</span>
        {r.defaultDb && <span className="text-2xs text-nv-textSubtle truncate max-w-[160px]">{r.defaultDb}</span>}
        {r.ok ? (
          <span className="text-2xs text-nv-textSubtle">
            {hasRows ? `${rowCount} row${rowCount === 1 ? '' : 's'}` : 'ok'} · {r.totalTimeMs}ms
          </span>
        ) : (
          <span className="text-2xs text-nv-danger">error</span>
        )}
      </button>
      {expanded && <ResultBody r={r} groupName={groupName} />}
    </div>
  );
}

/** Stacked "View all" section: sticky connection header + ResultBody. */
function AllViewSection({ r, groupName }: { r: any; groupName: string }) {
  const stmt = r.ok && r.statements?.length ? r.statements[0] : null;
  const hasRows = (stmt?.columns?.length ?? 0) > 0;
  const rowCount = stmt?.rows?.length ?? 0;
  return (
    <div>
      <div className="px-2 py-1 flex items-center gap-2 text-xs bg-nv-toolbar sticky top-0 z-10 border-b border-nv-border">
        {r.ok ? <CheckCircle2 size={12} className="text-nv-success" /> : <AlertCircle size={12} className="text-nv-danger" />}
        <span className="font-mono font-semibold truncate flex-1">{r.name}</span>
        <span className="text-2xs text-nv-textMuted">{r.engine}</span>
        {r.defaultDb && <span className="text-2xs text-nv-textSubtle truncate max-w-[160px]">{r.defaultDb}</span>}
        {r.ok ? (
          <span className="text-2xs text-nv-textSubtle">
            {hasRows ? `${rowCount} row${rowCount === 1 ? '' : 's'}` : 'ok'} · {r.totalTimeMs}ms
          </span>
        ) : (
          <span className="text-2xs text-nv-danger">error</span>
        )}
      </div>
      <ResultBody r={r} groupName={groupName} />
    </div>
  );
}
